const net = require("net");

const server = net.createServer((socket) => {
  socket.on("data", (data) => {
    console.log(data.toString("utf-8"));
  });

  const response = Buffer.from(
    "",
    "hex",
  );

  socket.write(response);
});

server.listen(3099, "127.0.0.1", () => {
  console.log("server opened");
});
